SELECT COUNT(*) 
FROM TBL_INSP_ITEM

  1=1
  AND PLANTCD = #{plant_cd}
  AND INSP_TP = #{insp_tp}
  AND ITEMGUBUN = #{item_gubun}
  AND TESTITEMGP = #{test_item_gp}
  AND TESTITEM LIKE #{test_item}
  AND GAUGE LIKE #{gauge}
  AND USEYN = #{use_yn}

SELECT 
  CODE, PLANTCD, INSP_TP, ITEMGUBUN, TESTITEMGP, TESTITEM,
  GAUGE, STANDARD, USEYN, REGUSERID, REGDTM, EDITUSERID, EDITDTM,
  FAILTYPE, FAILBREAKDOWN
FROM TBL_INSP_ITEM

  1=1
  AND PLANTCD = #{plant_cd}
  AND INSP_TP = #{insp_tp}
  AND ITEMGUBUN = #{item_gubun}
  AND TESTITEMGP = #{test_item_gp}
  AND TESTITEM LIKE #{test_item}
  AND GAUGE LIKE #{gauge}
  AND USEYN = #{use_yn}

ORDER BY REGDTM DESC, CODE DESC
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

